import { __decorate } from "tslib";
import __NG_CLI_RESOURCE__0 from "./button.scss?ngResource";
import { Component, Input, ContentChild, ElementRef } from '@angular/core';
import { CommonModule } from '@angular/common'; // <-- required
import { MatButtonModule } from '@angular/material/button';
import { IconComponent } from '../icon/icon.component';
let ButtonComponent = class ButtonComponent {
    constructor() {
        this.buttonText = true;
        this.label = 'Button';
        this.size = 'large';
        this.state = 'default';
        this.type = 'primary';
        this.hasLeftIcon = false;
        this.hasRightIcon = false;
    }
    ngAfterContentInit() {
        this.hasLeftIcon = !!this.leftIcon;
        this.hasRightIcon = !!this.rightIcon;
    }
    onHover() {
        if (this.state !== 'disabled')
            this.state = 'hover';
    }
    onLeave() {
        if (this.state !== 'disabled')
            this.state = 'default';
    }
    onPressed() {
        if (this.state !== 'disabled')
            this.state = 'pressed';
    }
    onReleased() {
        if (this.state !== 'disabled')
            this.state = 'default';
    }
    onClick() {
        if (this.state !== 'disabled')
            console.log('Button clicked');
    }
    static { this.propDecorators = {
        buttonText: [{ type: Input }],
        label: [{ type: Input }],
        size: [{ type: Input }],
        state: [{ type: Input }],
        type: [{ type: Input }],
        leftIcon: [{ type: ContentChild, args: ['leftIconSwap', { read: ElementRef },] }],
        rightIcon: [{ type: ContentChild, args: ['rightIconSwap', { read: ElementRef },] }]
    }; }
};
